/* ── BASE ── */
.button {
  display: inline-flex;
  flex-direction: row;
  align-items: center;
  justify-content: center;
  gap: var(--component-button-gap-md);
  padding: var(--component-button-padding-y-md) var(--component-button-padding-x-md);
  min-height: var(--component-button-min-height-md);

  font-family: var(--component-button-font-family);
  font-size: var(--component-button-font-size-md);
  font-weight: var(--component-button-font-weight);
  line-height: var(--component-button-line-height);
  text-align: center;
  white-space: nowrap;

  border-radius: var(--component-button-radius);
  border: var(--component-button-border-width) solid transparent;
  cursor: pointer;
  text-decoration: none;
  outline: none;
  box-sizing: border-box;
  transition: var(--component-button-transition);

  /* Default = Primary */
  background-color: var(--component-button-color-bg-primary);
  border-color: var(--component-button-color-border-primary);
  color: var(--component-button-color-text-primary);
}

/* ── FOCUS VISIBLE ── */
.button:focus-visible {
  outline: var(--component-button-focus-ring-width) solid var(--component-button-focus-ring-color);
  outline-offset: var(--component-button-focus-ring-offset);
}

/* ── DISABLED ── */
.button:disabled,
.button[aria-disabled="true"] {
  opacity: var(--component-button-opacity-disabled);
  cursor: not-allowed;
  pointer-events: none;
}

/* ══════════════════════════════════
   VARIANTS
══════════════════════════════════ */

/* Primary (default) */
.button--primary {
  background-color: var(--component-button-color-bg-primary);
  border-color: var(--component-button-color-border-primary);
  color: var(--component-button-color-text-primary);
}

.button--primary:hover:not(:disabled) {
  /* ⚠️ TOKEN_MANQUANT: component.button.color.bg.primary-hover — Figma: #1D4ED8 */
  background-color: var(--component-button-color-bg-primary-hover, #1D4ED8);
  border-color: var(--component-button-color-bg-primary-hover, #1D4ED8);
}

.button--primary:active:not(:disabled) {
  /* ⚠️ TOKEN_MANQUANT: component.button.color.bg.primary-active — Figma: (not specified, darker than hover) */
  filter: brightness(0.9);
}

.button--primary:disabled,
.button--primary[aria-disabled="true"] {
  background-color: var(--component-button-color-bg-disabled, #F3F4F6);
  border-color: var(--component-button-color-bg-disabled, #F3F4F6);
  /* ⚠️ TOKEN_MANQUANT: component.button.color.text.disabled — Figma: (not specified) */
  color: var(--component-button-color-text-secondary, #374151);
}

/* Secondary */
.button--secondary {
  background-color: var(--component-button-color-bg-secondary);
  border-color: var(--component-button-color-border-secondary);
  color: var(--component-button-color-text-secondary);
