}

.button--secondary:active:not(:disabled) {
  background-color: var(--component-button-color-bg-secondary-active, #F3F4F6);
}

/* Ghost */
.button--ghost {
  background-color: transparent;
  border-color: transparent;
  color: var(--component-button-color-text-ghost);
}

.button--ghost:hover:not(:disabled) {
  /* ⚠️ TOKEN_MANQUANT: component.button.color.bg.ghost-hover — Figma: (not specified) */
  background-color: var(--component-button-color-bg-ghost-hover, #F3F4F6);
}

.button--ghost:active:not(:disabled) {
  background-color: var(--component-button-color-bg-ghost-active, #E5E7EB);
}

/* Danger */
.button--danger {
  background-color: var(--component-button-color-bg-danger);
  border-color: var(--component-button-color-bg-danger);
  color: var(--component-button-color-text-danger);
}

.button--danger:hover:not(:disabled) {
