  width: var(--component-button-icon-size-sm);
  height: var(--component-button-icon-size-sm);
}

.button--md {
  gap: var(--component-button-gap-md);
  padding: var(--component-button-padding-y-md) var(--component-button-padding-x-md);
  min-height: var(--component-button-min-height-md);
  font-size: var(--component-button-font-size-md);
}

.button--md .button__icon {
  width: var(--component-button-icon-size-md);
  height: var(--component-button-icon-size-md);
}

.button--lg {
  gap: var(--component-button-gap-lg);
  padding: var(--component-button-padding-y-lg) var(--component-button-padding-x-lg);
  min-height: var(--component-button-min-height-lg);
  font-size: var(--component-button-font-size-lg);
}

.button--lg .button__icon {
  width: var(--component-button-icon-size-lg);
  height: var(--component-button-icon-size-lg);
}

/* ── ICON ELEMENT ── */
.button__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  width: var(--component-button-icon-size-md);
  height: var(--component-button-icon-size-md);
}

/* ── ICON-ONLY ── */
.button--icon-only {
  padding: var(--component-button-padding-y-md);
  aspect-ratio: 1;
}

.button--icon-only.button--sm {
  padding: var(--component-button-padding-y-sm);
}

.button--icon-only.button--lg {
  padding: var(--component-button-padding-y-lg);
}

/* ── FULL WIDTH ── */
.button--full-width {
  width: 100%;
}`;

const Button = ({
  variant = 'primary',
  size = 'md',
  disabled = false,
  iconLeft = null,
  iconRight = null,
  iconOnly = false,
  fullWidth = false,
  children,
  onClick,
  type = 'button',
  ariaLabel,
  ...rest
}) => {
  const cls = [
    'button',
    `button--${variant}`,
    `button--${size}`,
    iconOnly ? 'button--icon-only' : '',
    fullWidth ? 'button--full-width' : '',
  ].filter(Boolean).join(' ');

  return (
    <button
      className={cls}
      type={type}
      disabled={disabled}
      aria-disabled={disabled}
      aria-label={iconOnly ? ariaLabel : undefined}
      onClick={disabled ? undefined : onClick}
      {...rest}
    >
      {iconLeft && <span className="button__icon" aria-hidden="true">{iconLeft}</span>}
      {!iconOnly && <span className="button__label">{children}</span>}
      {iconOnly && <span className="button__icon" aria-hidden="true">{children}</span>}
      {iconRight && !iconOnly && <span className="button__icon" aria-hidden="true">{iconRight}</span>}
    </button>
  );
};

